mapper.select:
SELECT 
FROM appraisal_result
WHERE template_id = #{templateId} AND employee_id = #{employeeId}

SELECT r.employee_id, e.emp_no, e.emp_name, r.dept_id, d.dept_name, r.self_total_score, r.supervisor_total_score, r.final_total_score, r.appraisal_grade, r.overall_comment, r.result_status, r.confirm_status FROM appraisal_result r LEFT JOIN emp_employee e ON r.employee_id = e.id LEFT JOIN sys_department d ON r.dept_id = d.id WHERE 1 = 1
AND r.template_id = #{templateId}
AND r.dept_id = #{deptId}
AND r.appraisal_grade = #{appraisalGrade}
AND r.result_status = #{resultStatus}
ORDER BY r.final_total_score DESC

SELECT r.employee_id, CASE WHEN LENGTH(e.emp_name) > 1 THEN CONCAT(SUBSTRING(e.emp_name, 1, 1), '*') ELSE e.emp_name END AS emp_name, CONCAT(SUBSTRING(e.emp_no, 1, 1), '***') AS emp_no, r.dept_id, d.dept_name, r.self_total_score, r.supervisor_total_score, r.final_total_score, r.appraisal_grade, r.overall_comment, r.result_status, r.confirm_status FROM appraisal_result r LEFT JOIN emp_employee e ON r.employee_id = e.id LEFT JOIN sys_department d ON r.dept_id = d.id WHERE r.result_status = 'published'
AND r.template_id = #{templateId}
AND r.dept_id = #{deptId}
ORDER BY r.final_total_score DESC

