UPDATE appraisal_result
self_total_score = #{selfTotalScore}, supervisor_total_score = #{supervisorTotalScore}, final_total_score = #{finalTotalScore}, appraisal_grade = #{appraisalGrade}, grade_comment = #{gradeComment}, overall_comment = #{overallComment}, result_status = #{resultStatus}, confirm_status = #{confirmStatus}, confirm_time = #{confirmTime}, publish_start_time = #{publishStartTime}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT t.cycle_value, r.final_total_score, r.appraisal_grade,
       r.self_total_score, r.supervisor_total_score
FROM appraisal_result r
LEFT JOIN appraisal_template t ON r.template_id = t.id
WHERE r.employee_id = #{employeeId}
  AND t.is_deleted = 0
  AND r.result_status IN ('confirmed', 'published')

    AND t.cycle_value >= #{startCycle}


    AND t.cycle_value <= #{endCycle}

ORDER BY t.cycle_value ASC
